const{Collection:Collection}=require("discord.js"),CollectionCommand=require("./collectionCommand"),AlertsCommand=require("./alertsCommand");class CommandManager{constructor(){this.commands=new Collection,this.initialized=!1}async initialize(){return this.initialized||(await this.initializeCommands(),this.initialized=!0),this.initialized}async initializeCommands(){const collectionCommand=new CollectionCommand;this.commands.set(collectionCommand.getCommandData().name,collectionCommand);const alertsCommand=new AlertsCommand;await alertsCommand.initialize(),this.commands.set(alertsCommand.getCommandData().name,alertsCommand)}getCommands(){return Array.from(this.commands.values()).map((command=>command.getCommandData().toJSON()))}async executeCommand(interaction){const commandName=interaction.commandName;let command=this.commands.get(commandName);if(!command)try{this.initialized||(console.log("⚠️ Commands not initialized yet. Initializing now..."),await this.initialize(),command=this.commands.get(commandName))}catch(e){console.error("❌ Failed to initialize commands on-demand:",e.message)}if(command)try{await command.execute(interaction)}catch(error){console.error(`❌ Error executing command ${commandName}:`,error);const errorMessage="❌ Došlo k neočekávané chybě při spuštění příkazu.";interaction.deferred?await interaction.editReply({content:errorMessage}):await interaction.reply({content:errorMessage,ephemeral:!0})}else{const available=Array.from(this.commands.keys());console.error(`❌ Unknown command: ${commandName}. Available: ${available.join(", ")||"(none)"}`);try{await interaction.reply({content:"⚠️ Commands are updating. Please try again in a moment.",ephemeral:!0})}catch{}}}async cleanup(){for(const command of this.commands.values())command.disconnect&&await command.disconnect()}}module.exports=CommandManager;